        try:
            self._zkemkeeper_status = check_zkemkeeper_registration()
            st = self._zkemkeeper_status
            self.logger.info(
                "[ZKEMKeeper] ok=%s registryFound=%s comCreateOk=%s clsid=%s inproc=%s exists=%s err=%s",
                st.get("ok"),
                st.get("registryFound"),
                st.get("comCreateOk"),
                st.get("clsid"),
                st.get("inprocServer32"),
                st.get("inprocExists"),
                st.get("error"),
            )
        except Exception as e:
            self._zkemkeeper_status = {"ok": False, "error": str(e)}
            self.logger.warning("[ZKEMKeeper] status check failed: %s", e)

        self._update_manager = UpdateManager(app=self, cfg=self.cfg, logger=self.logger, api_factory=self._api)
        self._update_status: Optional[UpdateStatus] = None

        self._sync_after_id: int | None = None
        self._local_api: Optional[LocalAccessApiServerV2] = None

        self._enroll_state_lock = threading.Lock()
        self._enroll_running: bool = False
        self._enroll_cancel_event = threading.Event()

        self._device_sync_engine = DeviceSyncEngine(cfg=self.cfg, logger=self.logger)
        self._agent_engine = AgentRealtimeEngine(cfg=self.cfg, logger=self.logger)

        self._tray = None  # no tkinter tray

