    # ======================= Local API server =======================
    def _effective_local_api_bind(self) -> Tuple[str, int, bool]:
        host_cfg = str(getattr(self.cfg, "local_api_host", "127.0.0.1") or "127.0.0.1")
        port_cfg = int(getattr(self.cfg, "local_api_port", 8788) or 8788)
        enabled_cfg = bool(getattr(self.cfg, "local_api_enabled", True))

        gs: Dict[str, Any] = {}
        try:
            gs = get_backend_global_settings() or {}
        except Exception:
            gs = {}

        enabled_backend = bool(gs.get("access_server_enabled", True))
        host_backend = str(gs.get("access_server_host") or "").strip()
        port_backend = int(gs.get("access_server_port") or 0)

        host = host_backend if host_backend else host_cfg
        port = port_backend if port_backend > 0 else port_cfg
        enabled = bool(enabled_cfg and enabled_backend)

        if host and host not in ("127.0.0.1", "localhost", "0.0.0.0", "::1", ""):
            import socket
            try:
                test_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                test_sock.bind((host, 0))
                test_sock.close()
            except OSError:
                self.logger.warning("Backend host '%s' is not bindable, falling back to 127.0.0.1", host)
                host = "127.0.0.1"

        if not host:
            host = "127.0.0.1"
        return host, port, enabled

    def start_local_api_server(self):
        host, port, enabled = self._effective_local_api_bind()
        if not enabled:
            self.logger.info("Local API disabled (cfg or backend settings).")
            return

        if self._local_api:
            if self._local_api.host == host and self._local_api.port == port:
                return
            self.stop_local_api_server()

        try:
            self._local_api = LocalAccessApiServerV2(app=self, host=host, port=port)
            self._local_api.start()
            self.logger.info(f"Local API started on {host}:{port}")
        except Exception as e:
            self.logger.exception("Failed to start Local API: %s", e)

    def stop_local_api_server(self):
        if self._local_api:
            try:
                self._local_api.stop()
            except Exception:
                pass
        self._local_api = None

    def restart_local_api_server(self):
        self.stop_local_api_server()
        self.start_local_api_server()

    def get_local_api_health(self) -> Dict[str, Any]:
        auth = load_auth_token()
        reasons = self._restriction_reasons()
        summary = self.get_access_mode_summary()
        host, port, enabled = self._effective_local_api_bind()

        return {
            "ok": True,
            "loggedIn": bool(auth and auth.token),
            "restricted": bool(reasons),
            "reasons": reasons,
            "mode": self.get_access_global_mode(),
            "modeSummary": summary,
            "host": host,
            "port": port,
            "enabled": enabled,
            "zkemkeeper": getattr(self, "_zkemkeeper_status", None),
        }

